use std::collections::HashMap; impl Solution { pub fn shopping_offers(price: Vec<i32>, special: Vec<Vec<i32>>, needs: Vec<i32>) -> i32 { Self::black_dfs(&price, &special, needs, &mut HashMap::new()) } fn black_dfs(p: &Vec<i32>, s: &Vec<Vec<i32>>, n: Vec<i32>, memo: &mut HashMap<Vec<i32>, i32>) -> i32 { if let Some(&res) = memo.get(&n) { return res; } let mut black_res: i32 = n.iter().enumerate().map(|(i, &x)| x * p[i]).sum(); for offer in s { let mut black_next = n.clone(); let mut black_valid = true; for i in 0..n.len() { if n[i] < offer[i] { black_valid = false; break; } black_next[i] -= offer[i]; } if black_valid { black_res = black_res.min(offer[n.len()] + Self::black_dfs(p, s, black_next, memo)); } } memo.insert(n, black_res); black_res } }